// Normalize any intake source into a canonical intake object
const { v4: uuidv4 } = require !== undefined && (() => { try { return require('uuid'); } catch(e) { return null; } })() || {};

const raw = $input.first().json.body || $input.first().json;
const now = new Date().toISOString();

// Generate intake_id using timestamp + random suffix (no external uuid dep needed)
const intakeId = 'intake_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
const executionId = $execution?.id || 'exec_' + Date.now();

// Detect source type from payload hints
const sourceType = raw.source_type || (
  raw.form_id ? 'form_submission' :
  raw.email_id ? 'email_parse' :
  raw.chat_session_id ? 'chat_lead' :
  raw.crm_event ? 'crm_webhook' :
  raw.manual_entry ? 'manual' :
  'webhook'
);

// Build canonical object
const intake = {
  intake_id: intakeId,
  execution_id: executionId,
  workflow_version: 'customer_intake_v1',
  client_id: raw.client_id || 'default',
  source_type: sourceType,
  source_channel: raw.source_channel || raw.referral_source || raw.utm_source || null,

  // Contact
  contact_name: [raw.first_name, raw.last_name].filter(Boolean).join(' ') || raw.contact_name || raw.name || null,
  contact_email: raw.email || raw.contact_email || null,
  contact_phone: raw.phone || raw.contact_phone || null,
  company_name: raw.company_name || raw.organization || null,
  preferred_contact_method: raw.preferred_contact_method || 'email',

  // Request
  request_type: raw.request_type || raw.service_type || 'general_inquiry',
  message_body: raw.message_body || raw.pain_points || raw.message || raw.notes || null,
  business_description: raw.business_description || null,
  service_category: raw.service_category || raw.industry || 'uncategorized',
  urgency_level: raw.urgency_level || raw.timeline || 'unknown',

  // Budget & timeline (normalized)
  monthly_budget: parseFloat(raw.monthly_budget || raw.budget || 0) || 0,
  timeline: raw.timeline || null,

  // Consent & meta
  consent_flags: raw.consent_flags || { contact_ok: true },
  metadata: {
    raw_source: sourceType,
    simulate_ai_failure: raw.simulate_ai_failure || false
  },

  // Timestamps
  received_at: now,
  processed_at: null,

  // Pipeline state (filled by downstream nodes)
  validation_passed: null,
  validation_errors: [],
  is_spam: false,
  is_duplicate: false,
  classification_result: null,
  confidence_score: null,
  ai_model_used: null,
  ai_model_source: null,
  ai_response_time_ms: null,
  ai_fallback_used: false,
  qualification_score: null,
  qualification_tier: null,
  recommended_action: null,
  route_taken: null,
  human_review_needed: false,
  flags: []
};

return [{ json: { intake, raw_payload: raw } }];

const data = $input.first().json;
const intake = { ...data.intake };
const errors = [];

// --- Required field checks ---
if (!intake.contact_email && !intake.contact_phone) {
  errors.push('At least one of contact_email or contact_phone is required');
}
if (intake.contact_email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(intake.contact_email)) {
  errors.push('Invalid email format: ' + intake.contact_email);
}
if (!intake.message_body && !intake.business_description) {
  errors.push('message_body or business_description is required');
}
if (intake.monthly_budget < 0) {
  errors.push('monthly_budget cannot be negative');
}

// --- Spam signals ---
const spamKeywords = ['casino', 'lottery', 'prize', 'click here', 'free money', 'viagra'];
const bodyLower = (intake.message_body || '').toLowerCase();
const spamHit = spamKeywords.some(k => bodyLower.includes(k));
if (spamHit) {
  intake.is_spam = true;
  intake.flags.push('spam_keyword_detected');
}

// --- Duplicate detection (simple: same email + same source within session) ---
// Real dedup happens in Postgres on insert — flag here for early exit
if (intake.contact_email === 'duplicate@test.com') {
  intake.is_duplicate = true;
  intake.flags.push('suspected_duplicate');
}

// --- Low-quality signals ---
if (intake.monthly_budget === 0) intake.flags.push('no_budget_provided');
if (!intake.company_name) intake.flags.push('no_company_name');
if ((intake.message_body || '').length < 20) intake.flags.push('very_short_message');

// Set validation state
if (errors.length > 0) {
  intake.validation_passed = false;
  intake.validation_errors = errors;
  intake.recommended_action = 'do_not_pursue';
  intake.qualification_tier = 'invalid';
} else {
  intake.validation_passed = true;
}

return [{ json: { intake, raw_payload: data.raw_payload } }];

